class Solution:
    def countElements(self, nums):
        count = 0
        for i, x in enumerate(nums):
            has_smaller = any(y < x for j, y in enumerate(nums) if j != i)
            has_greater = any(y > x for j, y in enumerate(nums) if j != i)
            if has_smaller and has_greater:
                count += 1
        return count

